import PptxGenJS from 'pptxgenjs';

// ─── CATSKILL PARTNERS BRAND (from actual deck analysis) ──────────────────────
const NAVY    = '132240';
const GREEN   = '2D6A4F';
const GREEN2  = '1A4731';
const GOLD    = 'B8962E';
const WHITE   = 'FFFFFF';
const LGRAY   = 'F9F9F7';
const MGRAY   = 'C8C8C3';
const DGRAY   = '2C2C2C';
const FONT    = 'Calibri';

// ─── INSTITUTIONAL DESIGN STANDARDS ─────────────────────────────────────────
// Rule 1: Max 6 bullets per slide
// Rule 2: Max 10 words per bullet
// Rule 3: Graphics/charts/images preferred over bullets
// Rule 4: Institutional investor grade only — no amateur layouts

// ─── STOCK IMAGES (iStock licensed) ──────────────────────────────────────────
const IMGS = {
  sunset_office:    'data:image/jpeg;base64,',
  team_meeting:     'data:image/jpeg;base64,',
  exec_discussion:  'data:image/jpeg;base64,',
  glass_building:   'data:image/jpeg;base64,',
  business_meeting: 'data:image/jpeg;base64,',
  growth_chart:     'data:image/jpeg;base64,',
  data_meeting:     'data:image/jpeg;base64,',
  team_collab:      'data:image/jpeg;base64,',
  investor_data:    'data:image/jpeg;base64,',
};

// Image assignment by slide theme
const THEME_IMAGES = {
  cover:         IMGS.sunset_office,
  team:          IMGS.business_meeting,
  market:        IMGS.growth_chart,
  strategy:      IMGS.exec_discussion,
  sourcing:      IMGS.data_meeting,
  value:         IMGS.investor_data,
  fund:          IMGS.team_meeting,
  deal:          IMGS.glass_building,
  default:       IMGS.team_collab,
  closing:       IMGS.sunset_office,
};

function getThemeImage(title) {
  const t = (title||'').toLowerCase();
  if (t.includes('team') || t.includes('partner') || t.includes('bio')) return THEME_IMAGES.team;
  if (t.includes('market') || t.includes('supercycle') || t.includes('demand') || t.includes('growth')) return THEME_IMAGES.market;
  if (t.includes('strateg') || t.includes('thesis') || t.includes('approach')) return THEME_IMAGES.strategy;
  if (t.includes('sourc') || t.includes('pipeline') || t.includes('deal flow')) return THEME_IMAGES.sourcing;
  if (t.includes('value') || t.includes('playbook') || t.includes('creation') || t.includes('ebitda')) return THEME_IMAGES.value;
  if (t.includes('fund') || t.includes('terms') || t.includes('economics') || t.includes('lp')) return THEME_IMAGES.fund;
  if (t.includes('anchor') || t.includes('project') || t.includes('acqui')) return THEME_IMAGES.deal;
  return THEME_IMAGES.default;
}

// ─── ENFORCE BULLET DISCIPLINE ────────────────────────────────────────────────
function enforceRules(bullets) {
  if (!bullets) return [];
  const MAX_BULLETS = 6;
  const MAX_WORDS = 10;
  
  return bullets
    .slice(0, MAX_BULLETS)
    .map(b => {
      const words = b.trim().split(/\s+/);
      if (words.length > MAX_WORDS) {
        return words.slice(0, MAX_WORDS).join(' ') + '...';
      }
      return b.trim();
    })
    .filter(b => b.length > 2);
}

// ─── PARSE CLAUDE OUTPUT ──────────────────────────────────────────────────────
function parseSlides(text) {
  const slides = [];
  const re = /---SLIDE\s+\d+:\s*([^\n-]+)---\n([\s\S]*?)(?=---SLIDE|---MORGAN|\s*$)/gi;
  let match;
  while ((match = re.exec(text)) !== null) {
    const title = match[1].trim();
    const body  = match[2].trim();
    const headlineM = body.match(/HEADLINE:\s*([^\n]+)/i);
    const statM     = body.match(/STAT CALLOUT:\s*([^\n]+(?:\n[^\n]+)?)/i);
    const notesM    = body.match(/SPEAKER NOTES:\s*([\s\S]+?)(?=\n[A-Z]+:|$)/i);
    const sourceM   = body.match(/SOURCE:\s*([^\n]+)/i);
    const bulletSec = body.match(/BULLETS:\n([\s\S]+?)(?=\n[A-Z]+:|$)/i);
    
    let bullets = [];
    if (bulletSec) {
      bullets = bulletSec[1].split('\n')
        .map(l => l.replace(/^[-•*·]\s*/, '').trim())
        .filter(l => l && l.length > 3);
    }
    
    // Enforce institutional rules
    bullets = enforceRules(bullets);
    
    slides.push({
      title,
      headline: headlineM?.[1]?.trim() || '',
      bullets,
      stat: statM?.[1]?.trim() || '',
      notes: notesM?.[1]?.trim() || '',
      source: sourceM?.[1]?.trim() || '',
    });
  }
  
  // Fallback parsing
  if (slides.length < 2) {
    text.split(/\n{3,}/).filter(b => b.trim().length > 10).forEach((block, i) => {
      const lines = block.split('\n').filter(l => l.trim());
      if (!lines.length) return;
      const title = lines[0].replace(/^[#\d\.\-\*]+\s*/, '').replace(/\*\*/g,'').trim();
      const bullets = enforceRules(
        lines.slice(1)
          .map(l => l.replace(/^[-•*·\d\.]+\s*/, '').replace(/\*\*/g,'').trim())
          .filter(l => l.length > 3)
      );
      slides.push({ title, headline:'', bullets, stat:'', notes:'', source:'' });
    });
  }
  return slides;
}

// ─── SLIDE BUILDERS ───────────────────────────────────────────────────────────

function makePptx(titleStr) {
  const pptx = new PptxGenJS();
  pptx.layout  = 'LAYOUT_WIDE';
  pptx.author  = 'Catskill Partners';
  pptx.company = 'Catskill Partners';
  pptx.title   = titleStr || 'Catskill Partners';
  return pptx;
}

function addFooter(slide, n) {
  // Gold footer bar
  slide.addShape('rect', { x:0, y:7.3, w:'100%', h:0.08, fill:{color:GOLD}, line:{color:GOLD} });
  // Footer text
  slide.addText('CATSKILL PARTNERS  |  CONFIDENTIAL  |  info@catskillpartners.com', {
    x:0.22, y:7.32, w:11, h:0.18, fontFace:FONT, fontSize:7, color:MGRAY
  });
  if (n) slide.addText(`${n}`, { x:12.8, y:7.32, w:0.4, h:0.18, fontFace:FONT, fontSize:7, color:MGRAY, align:'right' });
}

// COVER SLIDE — full bleed image, text overlay
function buildCover(pptx, title, subtitle, audience, date) {
  const slide = pptx.addSlide();

  // Full bleed background image with dark overlay
  slide.addImage({ data: IMGS.sunset_office, x:0, y:0, w:'100%', h:'100%' });
  // Dark navy overlay for readability
  slide.addShape('rect', { x:0, y:0, w:'100%', h:'100%', fill:{color:'0A1628', transparency:20}, line:{color:'0A1628', transparency:20} });
  // Gold left accent
  slide.addShape('rect', { x:0, y:0, w:0.22, h:'100%', fill:{color:GOLD}, line:{color:GOLD} });
  // Gold bottom bar
  slide.addShape('rect', { x:0, y:7.3, w:'100%', h:0.2, fill:{color:GOLD}, line:{color:GOLD} });
  
  // CLARITY. CRAFT. CAPITAL.
  slide.addText('CLARITY. CRAFT. CAPITAL.', {
    x:0.55, y:1.0, w:10, h:0.42,
    fontFace:FONT, fontSize:12, bold:true, color:GOLD, charSpacing:4
  });
  slide.addText('We are operators first.', {
    x:0.55, y:1.45, w:8, h:0.35,
    fontFace:FONT, fontSize:12, color:'CCCCCC', italic:true
  });
  
  // Main title
  slide.addText(title, {
    x:0.55, y:2.05, w:12.4, h:2.2,
    fontFace:FONT, fontSize:44, bold:true, color:WHITE, valign:'top'
  });
  
  // Subtitle / audience
  if (subtitle || audience) {
    slide.addText((subtitle || audience), {
      x:0.55, y:4.4, w:10, h:0.5,
      fontFace:FONT, fontSize:18, color:MGRAY
    });
  }
  
  // Date
  slide.addText(date || new Date().toLocaleDateString('en-US',{month:'long',year:'numeric'}), {
    x:0.55, y:5.05, w:6, h:0.32,
    fontFace:FONT, fontSize:11, color:GOLD
  });
  
  // Contact
  slide.addText('info@catskillpartners.com  |  www.catskillpartners.com', {
    x:0.55, y:7.1, w:9, h:0.25,
    fontFace:FONT, fontSize:9, color:'AAAAAA'
  });
  return slide;
}

// SECTION DIVIDER — dark with number
function buildSection(pptx, title, n) {
  const slide = pptx.addSlide();
  const img = getThemeImage(title);
  
  slide.addImage({ data: img, x:0, y:0, w:'100%', h:'100%' });
  slide.addShape('rect', { x:0, y:0, w:'100%', h:'100%', fill:{color:GREEN2, transparency:25}, line:{color:GREEN2, transparency:25} });
  slide.addShape('rect', { x:0, y:0, w:0.22, h:'100%', fill:{color:GOLD}, line:{color:GOLD} });
  slide.addShape('rect', { x:0, y:7.3, w:'100%', h:0.2, fill:{color:GOLD}, line:{color:GOLD} });
  
  slide.addText(`0${n||''}`, {
    x:0.5, y:1.2, w:3, h:1.5,
    fontFace:FONT, fontSize:96, bold:true, color:GOLD, transparency:35
  });
  slide.addText(title, {
    x:0.5, y:2.9, w:12.5, h:1.8,
    fontFace:FONT, fontSize:42, bold:true, color:WHITE
  });
  slide.addText('CATSKILL PARTNERS', {
    x:0.5, y:6.9, w:6, h:0.4,
    fontFace:FONT, fontSize:9, color:GOLD, charSpacing:3
  });
  return slide;
}

// STAT CALLOUT SLIDE — full image bg, big number
function buildStatSlide(pptx, slideData, n) {
  const slide = pptx.addSlide();
  const img = getThemeImage(slideData.title);
  
  // Left content panel (70%) + right stat panel (30%)
  slide.background = { color: 'F9F9F7' };
  
  // Navy top header
  slide.addShape('rect', { x:0, y:0, w:'100%', h:0.72, fill:{color:NAVY}, line:{color:NAVY} });
  slide.addShape('rect', { x:0, y:0, w:0.08, h:'100%', fill:{color:GOLD}, line:{color:GOLD} });
  
  // Title in header
  slide.addText(slideData.title, {
    x:0.22, y:0.1, w:8.5, h:0.52,
    fontFace:FONT, fontSize:20, bold:true, color:WHITE, valign:'middle'
  });
  
  addFooter(slide, n);
  
  // Headline
  if (slideData.headline) {
    slide.addShape('rect', { x:0.22, y:0.82, w:8.5, h:0.46, fill:{color:'EBF5EE'}, line:{color:GREEN, pt:0.5} });
    slide.addText(slideData.headline, {
      x:0.35, y:0.82, w:8.3, h:0.46,
      fontFace:FONT, fontSize:13, bold:true, color:GREEN, valign:'middle'
    });
  }
  
  // Bullets (left, max 6, max 10 words each - already enforced)
  const bulletTop = slideData.headline ? 1.4 : 0.88;
  if (slideData.bullets.length > 0) {
    const bulletItems = slideData.bullets.map((b, i) => ({
      text: b,
      options: {
        bullet: { type:'number', style:'arabicPeriod', indent:18 },
        color: i===0 ? DGRAY : '555555',
        fontSize: i===0 ? 15 : 14,
        bold: i===0,
        fontFace: FONT,
        paraSpaceAfter: 10,
      }
    }));
    slide.addText(bulletItems, {
      x:0.22, y:bulletTop, w:8.5, h:5.8-bulletTop,
      valign:'top', fontFace:FONT
    });
  }
  
  // Right stat callout box
  if (slideData.stat) {
    const statParts = slideData.stat.split('\n');
    slide.addShape('rect', { x:9.05, y:0.82, w:4.06, h:6.38, fill:{color:NAVY}, line:{color:GOLD, pt:1.5} });
    slide.addShape('rect', { x:9.05, y:0.82, w:4.06, h:0.1, fill:{color:GOLD}, line:{color:GOLD} });
    slide.addText(statParts[0]||'', {
      x:9.05, y:1.5, w:4.06, h:1.8,
      fontFace:FONT, fontSize:54, bold:true, color:GOLD, align:'center', valign:'middle'
    });
    if (statParts.slice(1).join(' ')) {
      slide.addText(statParts.slice(1).join(' '), {
        x:9.15, y:3.5, w:3.86, h:1.6,
        fontFace:FONT, fontSize:13, color:WHITE, align:'center', wrap:true
      });
    }
    if (slideData.source) {
      slide.addText(`Source: ${slideData.source}`, {
        x:9.15, y:6.8, w:3.86, h:0.3,
        fontFace:FONT, fontSize:7.5, color:MGRAY, align:'center', italic:true
      });
    }
    // Right panel image accent (small, behind stat text area)
    slide.addImage({ data: img, x:9.05, y:5.0, w:4.06, h:1.9, transparency:65 });
  }
  return slide;
}

// IMAGE + CONTENT SLIDE — split layout, image right
function buildImageContentSlide(pptx, slideData, n) {
  const slide = pptx.addSlide();
  const img = getThemeImage(slideData.title);
  
  slide.background = { color: 'F9F9F7' };
  
  // Header
  slide.addShape('rect', { x:0, y:0, w:'100%', h:0.72, fill:{color:NAVY}, line:{color:NAVY} });
  slide.addShape('rect', { x:0, y:0, w:0.08, h:'100%', fill:{color:GOLD}, line:{color:GOLD} });
  slide.addText(slideData.title, {
    x:0.22, y:0.1, w:8.5, h:0.52,
    fontFace:FONT, fontSize:20, bold:true, color:WHITE, valign:'middle'
  });
  
  addFooter(slide, n);
  
  // Right side image (40% width)
  slide.addImage({ data: img, x:7.6, y:0.72, w:5.73, h:6.58 });
  // Overlay on image for brand consistency
  slide.addShape('rect', { x:7.6, y:0.72, w:5.73, h:6.58, fill:{color:NAVY, transparency:75}, line:{color:NAVY, transparency:75} });
  // Gold vertical divider
  slide.addShape('rect', { x:7.55, y:0.72, w:0.06, h:6.58, fill:{color:GOLD}, line:{color:GOLD} });
  
  // Headline
  const bulletTop = slideData.headline ? 1.42 : 0.88;
  if (slideData.headline) {
    slide.addShape('rect', { x:0.22, y:0.82, w:7.22, h:0.46, fill:{color:'EBF5EE'}, line:{color:GREEN, pt:0.5} });
    slide.addText(slideData.headline, {
      x:0.35, y:0.82, w:7.0, h:0.46,
      fontFace:FONT, fontSize:13, bold:true, color:GREEN, valign:'middle'
    });
  }
  
  // Bullets (left panel, already enforced 6/10)
  if (slideData.bullets.length > 0) {
    const bulletItems = slideData.bullets.map((b, i) => ({
      text: b,
      options: {
        bullet: { code:'2022', indent:14 },
        color: i===0 ? DGRAY : '555555',
        fontSize: i===0 ? 15 : 14,
        bold: i===0,
        fontFace: FONT,
        paraSpaceAfter: 12,
      }
    }));
    slide.addText(bulletItems, {
      x:0.22, y:bulletTop, w:7.22, h:5.6-bulletTop,
      valign:'top', fontFace:FONT
    });
  }
  
  // Speaker notes label on image side
  if (slideData.notes) {
    slide.addText(slideData.notes.slice(0,150), {
      x:7.7, y:5.8, w:5.5, h:1.3,
      fontFace:FONT, fontSize:9, color:WHITE, italic:true, wrap:true, transparency:10
    });
  }
  return slide;
}

// FULL BLEED IMAGE SLIDE (for visual impact / section intro)
function buildFullImageSlide(pptx, slideData, n) {
  const slide = pptx.addSlide();
  const img = getThemeImage(slideData.title);
  
  slide.addImage({ data: img, x:0, y:0, w:'100%', h:'100%' });
  slide.addShape('rect', { x:0, y:0, w:'100%', h:'100%', fill:{color:'0A1628', transparency:40}, line:{color:'0A1628', transparency:40} });
  slide.addShape('rect', { x:0, y:0, w:0.22, h:'100%', fill:{color:GOLD}, line:{color:GOLD} });
  slide.addShape('rect', { x:0, y:7.3, w:'100%', h:0.2, fill:{color:GOLD}, line:{color:GOLD} });
  
  if (slideData.headline || slideData.title) {
    slide.addText(slideData.headline || slideData.title, {
      x:0.5, y:2.8, w:12.5, h:1.5,
      fontFace:FONT, fontSize:36, bold:true, color:WHITE, align:'center'
    });
  }
  if (slideData.stat) {
    slide.addText(slideData.stat.split('\n')[0], {
      x:3, y:4.5, w:7, h:1.2,
      fontFace:FONT, fontSize:64, bold:true, color:GOLD, align:'center'
    });
  }
  addFooter(slide, n);
  return slide;
}

