  slide.addShape('rect', { x:0, y:0, w:0.22, h:'100%', fill:{color:GOLD}, line:{color:GOLD} });
  
  // Gold divider
  slide.addShape('rect', { x:0.22, y:5.5, w:13.11, h:0.05, fill:{color:GOLD}, line:{color:GOLD} });
  
